class ToolDriftMonitor:
    def __init__(self):
        self.schema_registry = {}

    def register_tool(self, tool_name: str, schema: type[BaseModel]):
        self.schema_registry[tool_name] = schema

    def check_drift(self, tool_call):
        schema = self.schema_registry.get(tool_call['name'])
        if schema:
            try:
                schema(**tool_call['args'])
                return True
            except Exception as e:
                return {'drift_detected': True, 'error': str(e)}
        return False

