from smolagents import Agent
import json

from typing import Dict, Any

class ResilientAgent(Agent):
    def __init__(self, *args, checkpoint_file='agent_state.json', **kwargs):
        super().__init__(*args, **kwargs)
        self.checkpoint_file = checkpoint_file
        self.step_results = {}

    def reasoning_step(self, step: int, input_data: Any) -> Any:
        try:
            result = self._execute_step(step, input_data)
            self.step_results[step] = {'status': 'success', 'output': result}
            self._save_checkpoint()
            return result
        except Exception as e:
            self.step_results[step] = {'status': 'error', 'error': str(e)}
            self._save_checkpoint()
            # Recovery: retry with simplified input
            return self._recover_step(step, input_data)

    def _recover_step(self, step: int, input_data: Any):
        print(f'Recovering step {step}')
        # Simplified reasoning fallback
        return str(input_data)

    def _save_checkpoint(self):
        with open(self.checkpoint_file, 'w') as f:
            json.dump(self.step_results, f)

resilient_agent = ResilientAgent()
